import { useState } from "react";
import { createStaff } from "../../api/adminUserApi";

export default function CreateStaff() {
  const [form, setForm] = useState({ name: "", email: "", password: "", role: "staff" });

  const submit = async (e) => {
    e.preventDefault();
    try {
      await createStaff(form);
      alert("Staff created!");
      setForm({ name: "", email: "", password: "", role: "staff" });
    } catch (err) {
      alert(err.response?.data?.message || "Failed");
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Create Staff / Manager</div>
          <div className="pageSub">Add a new team member to your organization</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 560, margin: "32px auto" }}>
        <form onSubmit={submit}>
          <label className="label">Full Name</label>
          <input className="input" placeholder="Enter full name" value={form.name}
            onChange={(e)=>setForm({ ...form, name: e.target.value })} required
          />

          <label className="label" style={{ marginTop: 20 }}>Email Address</label>
          <input className="input" placeholder="Enter email address" type="email" value={form.email}
            onChange={(e)=>setForm({ ...form, email: e.target.value })} required
          />

          <label className="label" style={{ marginTop: 20 }}>Password</label>
          <input className="input" placeholder="Enter password" type="password" value={form.password}
            onChange={(e)=>setForm({ ...form, password: e.target.value })} required
          />

          <label className="label" style={{ marginTop: 20 }}>Role</label>
          <select className="select" value={form.role}
            onChange={(e)=>setForm({ ...form, role: e.target.value })}
          >
            <option value="staff">Staff</option>
            <option value="manager">Manager</option>
          </select>

          <div style={{ marginTop: 28, display: "flex", gap: 12 }}>
            <button type="submit" className="btn btnPrimary">Create Staff</button>
            <button type="button" onClick={() => setForm({ name: "", email: "", password: "", role: "staff" })} className="btn">Clear</button>
          </div>
        </form>
      </div>
    </div>
  );
}
